import ProductCard from '../ProductCard';
import { products } from '../../products';
import './style.css';

export default function Container() {
  const onClickReadMore = (product) => {
    if (product.path) {
      window.open(product.path, '_blank', 'noopener,noreferrer');
    }
  };

  return (
    <main className="container products-container">
      {products.map((product) => (
        <ProductCard key={product.id} product={product} onClick={onClickReadMore} />
      ))}
    </main>
  );
}
